import { useState, useEffect, useRef, useCallback } from "react";

/**
 * Hook: Real-time trade execution streaming via WebSocket.
 * Connects to /api/ws/trades and pushes updates every 3 seconds.
 * Returns { recentTrades, newFills, totalCount }.
 * Calls onNewFill(trade) callback for each newly detected fill.
 */
export default function useTradeStream({ onNewFill } = {}) {
  const [recentTrades, setRecentTrades] = useState([]);
  const [totalCount, setTotalCount] = useState(0);
  const wsRef = useRef(null);
  const retryRef = useRef(0);
  const onNewFillRef = useRef(onNewFill);
  onNewFillRef.current = onNewFill;

  useEffect(() => {
    let active = true;

    const connectWs = () => {
      const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
      const url = `${protocol}//${window.location.host}/api/ws/trades`;

      try {
        const ws = new WebSocket(url);
        wsRef.current = ws;

        ws.onopen = () => {
          retryRef.current = 0;
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            if (!active) return;
            setRecentTrades(data.recent_trades || []);
            setTotalCount(data.total_count || 0);
            // Fire callback for each new fill
            if (data.new_fills && data.new_fills.length > 0 && onNewFillRef.current) {
              for (const fill of data.new_fills) {
                onNewFillRef.current(fill);
              }
            }
          } catch (e) {
            console.warn("[Trade WS] Parse error:", e);
          }
        };

        ws.onclose = () => {
          if (!active) return;
          const delay = Math.min(1000 * Math.pow(2, retryRef.current), 30000);
          retryRef.current++;
          setTimeout(connectWs, delay);
        };

        ws.onerror = () => {
          ws.close();
        };
      } catch {
        // WebSocket not supported — silently fail
      }
    };

    connectWs();

    return () => {
      active = false;
      if (wsRef.current) wsRef.current.close();
    };
  }, []);

  return { recentTrades, totalCount };
}
