import { useState, useEffect, useRef } from "react";
import { getApiBase } from '../utils/platform';

/**
 * Hook: Real-time P&L streaming via WebSocket.
 * Connects to /api/ws/pnl and pushes updates every second.
 * Falls back to HTTP polling if WebSocket unavailable.
 */
export default function usePnlStream(pollMs = 2000) {
  const [pnl, setPnl] = useState(null);
  const wsRef = useRef(null);
  const retryRef = useRef(0);

  useEffect(() => {
    let active = true;
    let fallbackInterval = null;

    const connectWs = () => {
      const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
      const url = `${protocol}//${window.location.host}/api/ws/pnl`;

      try {
        const ws = new WebSocket(url);
        wsRef.current = ws;

        ws.onopen = () => {
          retryRef.current = 0;
          if (fallbackInterval) {
            clearInterval(fallbackInterval);
            fallbackInterval = null;
          }
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            if (active) setPnl(data);
          } catch (e) {
            console.warn("[PnL WS] Parse error:", e);
          }
        };

        ws.onclose = () => {
          if (!active) return;
          // Exponential backoff retry
          const delay = Math.min(1000 * Math.pow(2, retryRef.current), 30000);
          retryRef.current++;
          setTimeout(connectWs, delay);
          // Start HTTP fallback while WS reconnects
          if (!fallbackInterval) {
            fallbackInterval = setInterval(fetchHttp, pollMs);
          }
        };

        ws.onerror = () => {
          ws.close();
        };
      } catch {
        // WebSocket not supported — use HTTP fallback
        if (!fallbackInterval) {
          fallbackInterval = setInterval(fetchHttp, pollMs);
        }
      }
    };

    const fetchHttp = async () => {
      try {
        const r = await fetch(`${getApiBase()}/pnl/snapshot`);
        if (r.ok) {
          const data = await r.json();
          if (active) setPnl(data);
        }
      } catch {
        // Ignore polling errors
      }
    };

    connectWs();

    return () => {
      active = false;
      if (wsRef.current) wsRef.current.close();
      if (fallbackInterval) clearInterval(fallbackInterval);
    };
  }, [pollMs]);

  return pnl;
}
